const jdNodes = $('Fetch Job Description').all();
const jd = jdNodes.length > 0 ? jdNodes[0].json : {};

// hr_assessments stores skills as Postgres text[] array e.g. {Node.js,PostgreSQL,Docker}
let skillsText = 'Programming';
try {
  if (Array.isArray(jd.skills)) {
    skillsText = jd.skills.join(', ');
  } else if (typeof jd.skills === 'string') {
    skillsText = jd.skills.replace(/[{}]/g, '');
  }
} catch(e) {}

// Include full JD if available for richer context
const jobDescContext = jd.job_description ? `\n\n**FULL JOB DESCRIPTION:**\n${jd.job_description}` : '';

const resumes = $input.all();

let combinedResumesText = '';
resumes.forEach((r, idx) => {
  combinedResumesText += `\n\n--- CANDIDATE RESUME ${idx + 1} ---\n${r.json.text || 'Error extracting text'}`;
});

const prompt = `### TASK
Evaluate EVERY candidate resume below against the job requirements. Return ONLY a JSON object with a "candidates" array — no markdown, no extra text.

### JOB REQUIREMENTS
- Position: ${jd.role_title || 'Software Engineer'}
- Required Skills: ${skillsText}
- Experience Level: ${jd.experience_level || 'Not Specified'}
- Coding Assessment Required: ${jd.include_coding ? 'Yes' : 'No'}${jobDescContext}

### CANDIDATE RESUMES TO ANALYZE
${combinedResumesText}

### SCORING RUBRIC — compute match_score (0-100) using EXACTLY these three weighted criteria:

**A. Required Skills Match (50 pts)**
For each required skill listed above, award points proportionally:
- Direct match (same exact technology): full credit
- Close equivalent (e.g. MySQL -> PostgreSQL, Flask -> FastAPI, Vue -> React, Express -> Node.js): 80% credit
- Adjacent/transferable (e.g. any SQL DB -> SQL skills, any JS framework -> JS skills): 50% credit
- No relevant overlap: 0 credit
A_score = (weighted_coverage_sum / max_possible) x 50

**B. Adjacent & Complementary Skills (25 pts)**
- 20-25: Rich complementary stack that clearly adds value to this role
- 10-19: Moderate adjacent skills with some relevance
- 0-9: Narrow or unrelated additional skills

**C. Experience & Career Trajectory (25 pts)**
- 22-25: Senior/Principal, domain-matched, complex production-grade projects
- 15-21: Mid-level, clearly relevant work, demonstrated growth pattern
- 8-14: Junior/associate with relevant experience or coursework, progression visible
- 0-7: Entry-level, no professional experience, or unrelated career background

**Calibration Anchors:**
- 85-100: >=70% required skills covered AND experience level aligns with the role
- 70-84: 50-70% required skills OR exceptional transferable profile
- 50-69: 30-50% required skills, adjacent technical domain
- 30-49: <30% required skills, solid generalist but significant gaps
- 0-29: Unrelated background, no meaningful technical overlap

**Consistency Check:** Before finalising, rank all candidates and verify every score gap of >=10 points reflects a clearly articulable difference in skills or seniority level.

### FIELD EXTRACTION — extract ONLY what is explicitly written in the resume, never infer or hallucinate:
- name: full name as written in resume
- email: email address (use "not_provided@resume.com" if absent)
- phone: phone number string, or "" if absent
- location: city/country string, or "" if absent
- current_company: most recent employer name, or "" if absent
- job_title: most recent job title from resume
- experience_years: total professional years as integer (0 if unknown)
- match_score: integer 0-100 calculated per the rubric above
- ai_analysis.key_strengths: 2-4 specific strengths relevant to THIS role, citing actual skills or projects from the resume
- ai_analysis.concerns: 0-3 genuine gaps for this role (empty array [] if none)
- ai_analysis.reasoning: 2-3 sentences citing specific technologies, years, or projects that explain why this score was assigned

### OUTPUT FORMAT
Return ONLY this structure — no markdown fences, no labels, no text outside the JSON:
{"candidates": [...]}`;

return {
  json: {
    aiPrompt: prompt,
    job_id: jd.id,
    role_title: jd.role_title || 'Software Engineer',
    skills: skillsText,
    experience_level: jd.experience_level || 'Not Specified',
    jid: jd.jid || null,
    include_coding: jd.include_coding || false,
    mcq_time_limit: jd.mcq_time_limit || 30
  }
};

