    console.log(`  ✅ Enriched: ${candidate.name} (${email})`);
  } else {
    console.log(`  ⚠️ No resume data for: ${candidate.name} (${email})`);
  }
  return {
    ...candidate,
    ...resumeData
  };
});
console.log(`\n✅ ENRICHMENT COMPLETE:`);
console.log(`  - Total candidates: ${enrichedCandidates.length}`);
console.log(`  - With resume data: ${enrichedCandidates.filter(c => c.resume_drive_id).length}`);
console.log(`  - Missing resume data: ${enrichedCandidates.filter(c => !c.resume_drive_id).length}`);
// Return enriched data in the same format as Store Assessment Data
return [{
  json: {
    ...storeData,  // Keep all original data
    candidatesData: enrichedCandidates  // Replace with enriched candidates
  }
}];

// ENHANCED Store Assessment Data - PostgreSQL Version with QUALIFYING SURVEY QUESTIONS
