// ✅ SHUFFLE FUNCTION for random question selection
function shuffleArray(array) {
  const shuffled = [...array];
  for (let i = shuffled.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
  }
  return shuffled;
}

// ✅ CONFIGURATION from assessment metadata
const questionPoolSize = mcqQuestions.length;
const questionsPerCandidate = Math.min(assessmentMetadata.questionsPerCandidate || mcqQuestions.length, mcqQuestions.length);

console.log(`✅ Questions per candidate: ${questionsPerCandidate}`);
console.log(`✅ Total pool size: ${questionPoolSize}`);
console.log(`✅ Survey questions to store: ${workflowSurveyQuestions.length}`);

// Validate we have enough questions
console.log(`Question pool has ${mcqQuestions.length} questions, assigning ${questionsPerCandidate} per candidate`);

// Process assessment sessions with UNIQUE QUESTIONS per candidate
const assessmentSessions = emailTasks.map((emailTask, index) => {
  const candidate = selectedCandidates.find(c => c.email === emailTask.to) || {};

  if (!emailTask.screeningId) {
    emailTask.screeningId = candidate.screeningId || `screening_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
  }

  // ✅ RANDOMLY SELECT UNIQUE QUESTIONS FOR THIS CANDIDATE
  const shuffledQuestions = shuffleArray(mcqQuestions);
  const selectedQuestions = shuffledQuestions.slice(0, questionsPerCandidate);

  console.log(`✅ Selected ${selectedQuestions.length} unique questions for ${candidate.name || emailTask.candidateName}`);

  return {
    screeningId: emailTask.screeningId,
    candidate: {
      name: emailTask.candidateName || candidate.name || 'Unknown Name',
      email: emailTask.to || candidate.email || 'unknown@email.com',
      phone: candidate.phone || 'Not provided',
      location: candidate.location || 'Not provided',
      currentCompany: candidate.currentCompany || 'Not provided',
      matchScore: candidate.matchScore || 0,
