      optionalSkills: assessmentMetadata.optionalSkills || 'None specified',
      experienceLevel: assessmentMetadata.targetExperience || '2-5 years',
      salaryBudget: 'Competitive',
      questionCount: questionsPerCandidate,
      timeLimit: assessmentMetadata.estimatedDuration || '30 minutes',
      difficulty: assessmentMetadata.difficulty || 'intermediate',
      focusAreas: assessmentMetadata.focusAreas || ['Comprehensive Assessment']
    },
    // ✅ UNIQUE QUESTIONS for this candidate
    questions: selectedQuestions.map((q, qIndex) => ({
      questionId: q.id || qIndex + 1,
      questionText: q.question || `Question ${qIndex + 1}`,
      options: {
        A: q.options?.A || '',
        B: q.options?.B || '',
        C: q.options?.C || '',
        D: q.options?.D || ''
      },
      correctAnswer: q.correctAnswer || 'A',
      category: q.category || 'General',
      difficulty: q.difficulty || 'medium',
      explanation: q.explanation || '',
      timeLimit: q.timeLimit || 90
    })),
    jid: jobRequirements.jid || null,
    createdAt: new Date().toISOString(),
    expiresAt: new Date(Date.now() + 3 * 24 * 60 * 60 * 1000).toISOString()
  };
});

console.log(`✅ Processed ${assessmentSessions.length} assessment sessions with unique questions`);

// Prepare data for PostgreSQL nodes
const candidatesData = [];
const jobRequirementsData = [];
const questionsData = [];

assessmentSessions.forEach(session => {
  // Candidate data for candidates table
  candidatesData.push({
    screening_id: session.screeningId,
    name: session.candidate.name,
    email: session.candidate.email,
    phone: session.candidate.phone,
    location: session.candidate.location,
    current_company: session.candidate.currentCompany,
    job_title: session.jobRequirements.jobTitle,
    match_score: session.candidate.matchScore,
    required_skills: session.jobRequirements.requiredSkills,
    experience_level: session.jobRequirements.experienceLevel,
    salary_expectation: session.candidate.salaryExpectation,
    expires_at: session.expiresAt,
    jid: session.jid || null,
    status: 'pending',
    survey_validation_status: 'pending', // ✅ NEW: Default survey status
    technical_assessment_unlocked: false // ✅ NEW: Default locked
  });

  // Job requirements data for job_requirements table
  jobRequirementsData.push({
    screening_id: session.screeningId,
    job_title: session.jobRequirements.jobTitle,
    required_skills: session.jobRequirements.requiredSkills,
    optional_skills: session.jobRequirements.optionalSkills,
    experience_level: session.jobRequirements.experienceLevel,
    salary_budget: session.jobRequirements.salaryBudget,
    question_count: session.jobRequirements.questionCount,
    time_limit: session.jobRequirements.timeLimit,
    difficulty: session.jobRequirements.difficulty,
    focus_areas: JSON.stringify(session.jobRequirements.focusAreas)
  });

  // ✅ UNIQUE Questions data for assessment_questions table
  session.questions.forEach(question => {
    questionsData.push({
      screening_id: session.screeningId,
      question_id: question.questionId,
      question_text: question.questionText,
      options: JSON.stringify(question.options),
      correct_answer: question.correctAnswer,
      category: question.category,
      difficulty: question.difficulty,
      explanation: question.explanation,
      time_limit: question.timeLimit
    });
  });
});

// ✅ SURVEY QUESTIONS Data Preparation with EXPECTED ANSWERS
const surveyQuestionsData = [];

assessmentSessions.forEach(session => {
  workflowSurveyQuestions.forEach((question, qIndex) => {
    surveyQuestionsData.push({
      screening_id: session.screeningId,
      question_id: question.surveyQuestionId || (qIndex + 1),
      question_text: question.fieldLabel,
      question_type: question.fieldType === 'dropdown' ? 
        (question.fieldOptions?.values?.length === 2 && 
         question.fieldOptions.values.some(opt => opt.option === 'Yes') ? 'yes_no' : 'multiple_choice') 
        : 'text',
      options: question.fieldOptions ? JSON.stringify(question.fieldOptions) : null,
      expected_answer: question.expectedAnswer || null, // ✅ NEW: Store expected answer
      is_qualifying: question.isQualifying || false, // ✅ NEW: Store qualifying flag
      question_category: question.questionCategory || 'informational', // ✅ NEW: Store category
      validation_type: question.validationType || 'none', // ✅ NEW: Store validation type
      created_at: new Date().toISOString()
    });
  });
});

